import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, useMapEvents } from 'react-leaflet';
import { X } from 'lucide-react';

function LocationMarker({ position, setPosition }) {
  useMapEvents({ 
    click(e) { 
      setPosition([e.latlng.lat, e.latlng.lng]); 
    } 
  });
  return position ? <Marker position={position} /> : null;
}

const ModalNuevaSucursal = ({ onClose, onSave }) => {
  const [nombre, setNombre] = useState('');
  const [direccion, setDireccion] = useState('');
  const [provincia, setProvincia] = useState('Tucumán');
  const [ciudad, setCiudad] = useState('');
  const [coords, setCoords] = useState([-26.816, -65.216]);

  // Lista simplificada solo con Ciudades
  const ubicacionesData = {
    'Tucumán': ['San Miguel de Tucumán', 'Yerba Buena', 'Tafí Viejo', 'Concepción', 'Lules'],
    'Salta': ['Salta Capital', 'Cafayate', 'San Lorenzo'],
    'Santiago del Estero': ['Capital', 'La Banda']
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    if(!ciudad) return alert("Por favor, selecciona la ciudad");
    
    // Se envía el objeto sin el campo "zona"
    onSave({ nombre, direccion, provincia, ciudad, coords });
  };

  return (
    <div style={modalOverlay}>
      <div style={modalContent}>
        <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '15px', alignItems: 'center' }}>
          <h3 style={{ margin: 0, color: '#1e293b' }}>Nueva Sucursal</h3>
          <X onClick={onClose} style={{ cursor: 'pointer', color: '#64748b' }} />
        </div>

        <form onSubmit={handleSubmit}>
          <div style={{ marginBottom: '10px' }}>
            <label style={labelStyle}>Nombre del Local</label>
            <input 
              placeholder="Ej: Mi Tienda Centro" 
              style={inputStyle} 
              required 
              value={nombre} 
              onChange={e => setNombre(e.target.value)} 
            />
          </div>
          
          <div style={{ display: 'flex', gap: '10px', marginBottom: '10px' }}>
            <div style={{ flex: 1 }}>
              <label style={labelStyle}>Provincia</label>
              <select style={inputStyle} value={provincia} onChange={e => {setProvincia(e.target.value); setCiudad('');}}>
                {Object.keys(ubicacionesData).map(p => <option key={p} value={p}>{p}</option>)}
              </select>
            </div>
            <div style={{ flex: 1 }}>
              <label style={labelStyle}>Ciudad</label>
              <select style={inputStyle} required value={ciudad} onChange={e => setCiudad(e.target.value)}>
                <option value="">Seleccionar</option>
                {ubicacionesData[provincia].map(c => <option key={c} value={c}>{c}</option>)}
              </select>
            </div>
          </div>

          <div style={{ marginBottom: '10px' }}>
            <label style={labelStyle}>Dirección Exacta</label>
            <input 
              placeholder="Calle y altura" 
              style={inputStyle} 
              required 
              value={direccion} 
              onChange={e => setDireccion(e.target.value)} 
            />
          </div>
          
          <label style={labelStyle}>Ubicación en el Mapa (Clic para marcar)</label>
          <div style={{ height: '180px', margin: '5px 0 15px 0', borderRadius: '12px', overflow: 'hidden', border: '1px solid #e2e8f0' }}>
            <MapContainer center={coords} zoom={13} style={{ height: '100%' }}>
              <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
              <LocationMarker position={coords} setPosition={setCoords} />
            </MapContainer>
          </div>

          <button type="submit" style={btnSubmitModal}>Registrar Sucursal</button>
        </form>
      </div>
    </div>
  );
};

/* --- ESTILOS --- */
const modalOverlay = { position: 'fixed', top: 0, left: 0, width: '100%', height: '100%', background: 'rgba(15, 23, 42, 0.7)', display: 'flex', justifyContent: 'center', alignItems: 'center', zIndex: 2000, backdropFilter: 'blur(4px)' };
const modalContent = { background: 'white', padding: '30px', borderRadius: '20px', width: '450px', boxShadow: '0 20px 25px -5px rgba(0,0,0,0.1)' };
const labelStyle = { display: 'block', fontSize: '0.8rem', fontWeight: 'bold', color: '#64748b', marginBottom: '5px', marginLeft: '2px' };
const inputStyle = { width: '100%', padding: '12px', borderRadius: '10px', border: '1px solid #e2e8f0', boxSizing: 'border-box', outline: 'none', fontSize: '0.9rem' };
const btnSubmitModal = { width: '100%', padding: '14px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '12px', fontWeight: 'bold', cursor: 'pointer', fontSize: '1rem', transition: 'background 0.2s' };

export default ModalNuevaSucursal;
